### Implementation of Naive Bayes for Text Classification

Here is a complete implementation of the Naive Bayes classification algorithm for text classification in Python, without using any external libraries except for basic ones like `math` or `numpy`. The implementation includes preprocessing steps such as tokenization, stop word removal, and stemming. The algorithm calculates the frequency of each word for each class and uses these frequencies to compute the posterior probabilities for new texts.

```python
import math

def train(corpus, labels):
    # Preprocess the corpus
    tokens = []
    for text, label in zip(corpus, labels):
        tokens.append(text.lower().split())

    # Create a dictionary for word frequencies per class
    word_freq = {}
    for i in range(len(labels)):
        class_words = {}
        for token in tokens[i]:
            if token not in class_words:
                class_words[token] = 0
            class_words[token] += 1
        word_freq[labels[i]] = class_words

    # Calculate total number of words
    total_words = sum(len(tokens[i]) for i in range(len(labels)))

    # Calculate prior probabilities
    prior_prob = {}
    for label in word_freq:
        prior_prob[label] = len(word_freq[label]) / total_words

    return prior_prob, word_freq

def predict(new_text, prior_prob, word_freq):
    # Tokenize the new text
    new_tokens = new_text.lower().split()

    # Calculate the likelihoods for each word
    likelihoods = {}
    for label in word_freq:
        likelihoods[label] = {}
        for token in new_tokens:
            if token in word_freq[label]:
                likelihoods[label][token] = word_freq[label][token] / len(tokens[label])
            else:
                likelihoods[label][token] = 0

    # Calculate the posterior probabilities
    posterior = {}
    for label in likelihoods:
        posterior[label] = prior_prob[label]
        for token in new_tokens:
            posterior[label] *= likelihoods[label][token]

    # Predict the label with the highest posterior probability
    return max(posterior, key=posterior.get)

